scwin.filterSubCompanyNcallMenu = function (menuList) {
  if (scwin.getCoClsCd() == "0" || scwin.getCoClsCd() == "") {
    return menuList || [];
  }
  return (menuList || []).filter(function (menu) {
    const menuId = (menu && menu.menuId || "").toLowerCase();
    const menuNm = menu && menu.menuNm || "";
    return menuId.indexOf("n") === -1 && menuNm.indexOf("엔콜") === -1;
  });
};
scwin.menuOpenStateTimer = null;
scwin.serverMode = window.location.hostname.indexOf("newdevdebis.dongwon.com") > -1 ? "dev" : window.location.hostname.indexOf("newdebis.dongwon.com") > -1 ? "prd" : "local";
scwin.useMenuOpenState = true;
scwin.useMenuOpenStateBlock = scwin.serverMode === "prd";
scwin.isMenuClosed = function (node) {
  const openYn = node && node.openYn != null ? String(node.openYn).trim().toUpperCase() : "";
  return openYn === "0";
};
scwin.hasMenuProgram = function (node) {
  const programId = node ? node.actPgmId || node.pgmId || "" : "";
  return String(programId).trim() !== "";
};
scwin.applyTreeMenuOpenState = function (treeView, menuList) {
  if (!treeView || !treeView.removeNodeClass || !treeView.setNodeClass) {
    return;
  }
  for (const row of menuList) {
    const nodeId = row ? row.menuId : "";
    if (!nodeId) {
      continue;
    }
    treeView.removeNodeClass(nodeId, false, "tvw_red");
    treeView.removeNodeClass(nodeId, false, "tvw_gray");
    treeView.removeNodeClass(nodeId, false, "txt-red");
    treeView.removeNodeClass(nodeId, false, "txt-gray");
    if (scwin.useMenuOpenState && scwin.hasMenuProgram(row) && scwin.isMenuClosed(row)) {
      treeView.setNodeClass(nodeId, "txt-gray");
    }
  }
};
scwin.applyMenuOpenState = function () {
  scwin.applyTreeMenuOpenState(trv_treeview, ds_trvMenu.getAllJSON() || []);
  scwin.applyTreeMenuOpenState(trv_myTree, ds_fav.getAllJSON() || []);
};
scwin.scheduleApplyMenuOpenState = function () {
  if (scwin.menuOpenStateTimer) {
    clearTimeout(scwin.menuOpenStateTimer);
  }
  scwin.menuOpenStateTimer = setTimeout(function () {
    scwin.applyMenuOpenState();
  }, 0);
};
scwin.searchMenuSnapshot = [];
scwin.searchInProgress = false;
scwin.searchAlertOpen = false;
scwin.searchEnterLocked = false;
scwin.searchEnterLockTimer = null;
scwin.lockSearchEnter = function (delay) {
  if (scwin.searchEnterLockTimer) {
    clearTimeout(scwin.searchEnterLockTimer);
  }
  scwin.searchEnterLocked = true;
  scwin.searchEnterLockTimer = setTimeout(function () {
    scwin.searchEnterLocked = false;
    scwin.searchEnterLockTimer = null;
  }, delay || 300);
};
scwin.showSearchAlert = function (message, focusInput) {
  scwin.searchAlertOpen = true;
  scwin.lockSearchEnter(300);
  try {
    ibx_input3.blur();
  } catch (e) {}
  $c.win.alert($p, message, function () {
    scwin.lockSearchEnter(300);
    setTimeout(function () {
      scwin.searchAlertOpen = false;
      if (focusInput) {
        try {
          ibx_input3.focus();
        } catch (e) {}
      }
    }, 0);
  });
};
scwin.ensureOriginTrvMenu = function (menuList) {
  const originMenuList = ds_originTrvMenu.getAllJSON() || [];
  const currentMenuList = menuList || ds_trvMenu.getAllJSON() || [];
  if (originMenuList.length === 0 && currentMenuList.length > 0) {
    ds_originTrvMenu.setJSON(currentMenuList);
  }
};
scwin.getRestoreTrvMenu = function () {
  const originMenuList = ds_originTrvMenu.getAllJSON() || [];
  if (originMenuList.length > 0) {
    return originMenuList;
  }
  return scwin.searchMenuSnapshot || [];
};
scwin.getCurrentSysCd = function () {
  let sysCd = "";
  try {
    if ($p.top().wfm_header && $p.top().wfm_header.getWindow) {
      const headerWin = $p.top().wfm_header.getWindow();
      if (headerWin && headerWin.dma_userParam) {
        sysCd = headerWin.dma_userParam.get("sysCd") || "";
      }
      if (!sysCd && headerWin && headerWin.scwin) {
        sysCd = headerWin.scwin.sysCd || "";
      }
    }
  } catch (e) {}
  try {
    if (!sysCd) {
      sysCd = WebSquare.localStorage.getItem("sysCd") || "";
    }
  } catch (e) {}
  return sysCd;
};
scwin.useLocalMenuSearch = function () {
  try {
    if ($p.top().wfm_header && $p.top().wfm_header.getWindow) {
      const headerWin = $p.top().wfm_header.getWindow();
      if (headerWin && headerWin.ds_menuTop) {
        return headerWin.ds_menuTop.getRowCount() === 0;
      }
    }
  } catch (e) {}
  return false;
};
scwin.normalizeMenuSearchText = function (value) {
  return String(value || "").replace(/\s+/g, "").toLowerCase();
};
scwin.getLocalMenuSource = function () {
  const originMenuList = ds_originTrvMenu.getAllJSON() || [];
  if (originMenuList.length > 0) {
    return originMenuList;
  }
  if ((scwin.searchMenuSnapshot || []).length > 0) {
    return scwin.searchMenuSnapshot;
  }
  return ds_trvMenu.getAllJSON() || [];
};
scwin.searchMenuLocal = function (keyword) {
  const sourceMenuList = scwin.getLocalMenuSource();
  const normalizedKeyword = scwin.normalizeMenuSearchText(keyword);
  if (!normalizedKeyword || sourceMenuList.length === 0) {
    return [];
  }
  const menuMap = {};
  const includedMenuMap = {};
  for (const row of sourceMenuList) {
    menuMap[row.menuId] = row;
  }
  const includeAncestors = function (menuId) {
    let currentMenuId = menuId;
    while (currentMenuId && menuMap[currentMenuId]) {
      if (includedMenuMap[currentMenuId]) {
        break;
      }
      includedMenuMap[currentMenuId] = true;
      currentMenuId = menuMap[currentMenuId].upperMenuId || "";
    }
  };
  const includeDescendants = function (startIndex) {
    const baseDepth = Number(sourceMenuList[startIndex].lvl) || 0;
    for (let index = startIndex + 1; index < sourceMenuList.length; index++) {
      const currentDepth = Number(sourceMenuList[index].lvl) || 0;
      if (currentDepth <= baseDepth) {
        break;
      }
      includedMenuMap[sourceMenuList[index].menuId] = true;
    }
  };
  for (let index = 0; index < sourceMenuList.length; index++) {
    const row = sourceMenuList[index];
    const searchTarget = scwin.normalizeMenuSearchText([row.menuNm, row.actPgmNm, row.actPgmId].join(" "));
    if (searchTarget.indexOf(normalizedKeyword) > -1) {
      includedMenuMap[row.menuId] = true;
      includeAncestors(row.menuId);
      includeDescendants(index);
    }
  }
  return sourceMenuList.filter(function (row) {
    return !!includedMenuMap[row.menuId];
  });
};
scwin.applySearchResult = function (menuList) {
  ds_trvMenu.setJSON(menuList || []);
  trv_treeview.spanAll(true);
  scwin.scheduleApplyMenuOpenState();
};
scwin.restoreSearchResult = function () {
  ds_trvMenu.setJSON(scwin.getRestoreTrvMenu());
  scwin.scheduleApplyMenuOpenState();
};
scwin.dlt_menu_ondataload = function () {
  if (!scwin.searchInProgress) {
    scwin.ensureOriginTrvMenu();
  }
  scwin.scheduleApplyMenuOpenState();
};
