scwin.myMenuSearch = function () {
  dma_userParam.set("userId", WebSquare.localStorage.getItem("userId") || $c.data.getMemInfo($p, "userId"));
  $c.sbm.execute($p, sbm_getMyMenuList);
};

// 마이메뉴
scwin.trv_myTreeview_onlabelclick = function (value, node, index) {
  //debugger;
  if (scwin.useMenuOpenStateBlock && scwin.hasMenuProgram(node) && scwin.isMenuClosed(node)) {
    $c.win.alert($p, "해당 화면은 현재 점검 및 준비 중 입니다.");
    return;
  }
  if (node.pgmScrPath && node.pgmId) {
    trv_myTree.spanAll(false);
    const resolvedSysCd = scwin.applySearchMenuContext(node);
    let prefix = "/ui";
    prefix += node.pgmScrPath.substring(0, 1) !== "/" ? "/" : "";
    if (node.pgmScrPath.indexOf("/sample") > -1 || node.pgmScrPath.indexOf("/pub") > -1 || node.pgmScrPath.indexOf("/ui") > -1) {
      prefix = "";
    }
    let src = prefix + node.pgmScrPath + node.pgmId;
    src = src.replace(/.jsp/g, ".xml");
    //debugger;
    $c.win.openMenu($p, node.menuNm, src, node.pgmId, null, {
      pgmNm: node.pgmNm,
      menuId: node.menuId,
      sysCd: resolvedSysCd || node.sysCd,
      menuParam: node.menuParam
    });
    trv_myTree.findNodeByIndex(index, true);
  }
};
scwin.ibx_input3_oneditkeyup = function (info, e) {
  if (info.keyCode == 13) {
    if (scwin.searchAlertOpen || scwin.searchEnterLocked || scwin.searchInProgress) {
      return;
    }
    scwin.lockSearchEnter();
    let val = info.newValue;
    scwin.searchMenu(val);
  }
};
// 메뉴검색
scwin.searchMenu = function (val) {
  //debugger;
  if (scwin.searchAlertOpen || scwin.searchInProgress) {
    return;
  }
  if (!val) {
    scwin.showSearchAlert("검색어를 입력해주세요", true);
    return;
  } else {
    let memObj = $c.data.getMemInfo($p);
    const searchKeyword = val.trimAll();
    let sysCd = sbx_selectbox1.getValue();
    if (!sysCd) {
      sysCd = scwin.getCurrentSysCd();
    }
    if (sysCd && sysCd !== "all") {
      dma_search.set("sysCd", sysCd);
      dma_search.set("coCd", memObj.coCd);
    } else {
      dma_search.set("sysCd", "");
      if (memObj.coCd === "000") {
        dma_search.set("coCd", "tobe");
      } else if (memObj.coCd === "") {
        dma_search.set("coCd", "blankDsSearch");
      } else if (memObj.coCd === "017") {
        dma_search.set("coCd", "tobe017");
      } else {
        dma_search.set("coCd", "tobeCompany");
      }
    }

    // if(memObj.userClsCd == "01") {
    // } else {
    // }
    scwin.searchMenuSnapshot = ds_trvMenu.getAllJSON() || [];
    scwin.searchInProgress = true;
    if (scwin.useLocalMenuSearch()) {
      const localMenuList = scwin.searchMenuLocal(searchKeyword);
      scwin.searchInProgress = false;
      if (localMenuList.length === 0) {
        scwin.showSearchAlert("조회된 데이터가 없습니다.");
        scwin.restoreSearchResult();
        return;
      }
      scwin.applySearchResult(localMenuList);
      return;
    }
    dma_search.set("userId", memObj.userId);
    dma_search.set("menuNm", searchKeyword);
    $c.sbm.execute($p, sbm_allMenuList);
  }
};
scwin.sbm_allMenuList_submitdone = function (e) {
  var menuArray = e.responseJSON && e.responseJSON.GAUCE || [];
  for (const row of menuArray) {
    switch (row.actPgmId) {
      case "op_304_01_01b.jsp":
        row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
        break;
      case "op_304_01_02b.jsp":
        row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
        break;
      case "as_102_01_02b.jsp":
        row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
        break;
      case "as_102_01_03b.jsp":
        row.actPgmScrPath = "/ds/as/cstmrsrvc/coafmgnt/";
        break;
      case "op_301_01_05b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_301_01_19b.jsp"; //반입등록
        }
        break;
      case "op_301_01_06b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_301_01_09b.jsp"; //반출등록
        }
        break;
      case "op_304_01_06b.jsp":
        row.actPgmScrPath = "/ds/op/wrkrslts/transwrkrslts/";
        break;
      case "fs_103_03_01b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "fs_103_03_02b.jsp"; //협력업체 세금계산서 발행
        }
        break;
      case "op_204_04_01b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
          row.actPgmId = "tn_304_03_09b.jsp"; //CY구역관리
        }
        break;
      case "op_301_01_17b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_301_01_20b.jsp"; //반출입 정보 수정
        }
        break;
      case "op_304_01_65b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmScrPath = "/tn/op/transwrkindict/cntr/";
          row.actPgmId = "tn_304_01_12b.jsp"; //출도착등록(컨테이너)(협럭업체용)
        }
        break;
      case "op_202_02_07b.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "op_202_02_08b.jsp"; //셔틀운송작업물량차량조회
        }
        break;
      case "sd_402_01_35t.jsp":
        if (row.menuId.indexOf("n") !== -1) {
          row.actPgmId = "sd_402_01_35b.jsp"; //오더요청등록(크나우프)
        }
        break;
    }
  }
  menuArray = scwin.filterSubCompanyNcallMenu(menuArray);
  scwin.searchInProgress = false;
  if (menuArray.length == 0) {
    const localMenuList = scwin.searchMenuLocal(dma_search.get("menuNm"));
    if (localMenuList.length > 0) {
      scwin.applySearchResult(localMenuList);
      return;
    }
    scwin.showSearchAlert("조회된 데이터가 없습니다.");
    scwin.restoreSearchResult();
    return;
  }
  scwin.applySearchResult(menuArray);
};

